openscad:
diameter = 42; // [30:60]
thickness = 10; // [6:15]
strap_width = 22; // [18:30]
strap_length = 65; // [40:100]
bezel_height = 3; // [1:5]
hand_length_h = 12; // [8:18]
hand_length_m = 16; // [10:22]
$fn = 60;

color("black")
union() {
    // Case
    cylinder(h=thickness, d=diameter, center=true);

    // Bezel
    translate([0,0,thickness/2 - bezel_height/2])
        cylinder(h=bezel_height, d=diameter+4, center=true);

    // Straps
    translate([0, diameter/2 + strap_width/2 - 2, 0])
        cube([strap_width, strap_length, thickness-2], center=true);
    translate([0, -diameter/2 - strap_width/2 + 2, 0])
        cube([strap_width, strap_length, thickness-2], center=true);

    // Crown
    translate([diameter/2 + 3, 0, 0])
        rotate([0,90,0])
            cylinder(h=6, d=6, center=true);
}

color("white")
translate([0,0,thickness/2 - 1])
    cylinder(h=2, d=diameter-6, center=true);

color("black") {
    // Hour markers
    for (i = [0:11]) {
        rotate([0,0,i*30])
            translate([0, diameter/2 - 8, thickness/2 - 0.5])
                cube([2,6,1], center=true);
    }

    // Hour hand
    rotate([0,0,30])
        translate([0, hand_length_h/2 - 2, thickness/2 + 0.5])
            cube([3, hand_length_h, 1.5], center=true);

    // Minute hand
    rotate([0,0,150])
        translate([0, hand_length_m/2 - 2, thickness/2 + 1])
            cube([2, hand_length_m, 1.5], center=true);

    // Center pin
    translate([0,0,thickness/2 + 1.5])
        cylinder(h=3, d=3, center=true);
}
